{"language": "plaintext", "code": "/*─────────────────────────────────────────────────────────────────────────────
  CascadeGate_SPX500_Calibrator.mq5
  Script de calibración de parámetros para SPX500 — FASE 0 OBLIGATORIA

  PROPÓSITO:
    Extrae percentiles de ATR y ADX durante la sesión operativa (NYSE open)
    y genera un análisis de WR aproximado por bucket para identificar
    dead zones. Los valores resultantes se usan para parametrizar el EA.

  USO:
    1. Abrir gráfico M5 de SPX500 en FundingPips
    2. Arrastrar este script al gráfico
    3. Ejecutar con Inp_UseIS=true para datos IS (2021-2023)
    4. Revisar el CSV generado + logs en el Diario de MT5
    5. Repetir con Inp_UseIS=false para datos completos (comparación)

  OUTPUT:
    - CSV en carpeta Common de MT5 con percentiles ATR/ADX y análisis WR
    - Logs detallados en el Diario

  NOTA SOBRE WR APROXIMADO:
    El WR calculado aquí es una aproximación direccional basada en si
    el precio avanzó más hacia arriba que hacia abajo en las siguientes
    12 barras M5. NO es el WR real con SL/TP — ese requiere backtest
    completo en el tester de estrategias. Usar solo como guía relativa
    para identificar zonas de comportamiento inferior.
─────────────────────────────────────────────────────────────────────────────*/

#property copyright "CascadeGate Trading System"
#property version   "1.00"
#property script_show_inputs
#property description "Calibrador de parámetros ATR/ADX para CascadeGate SPX500"

//─── INPUTS ────────────────────────────────────────────────────────────────────

input group "=== SÍMBOLO Y DATOS ==="
input string   Inp_Symbol          = "";          // Símbolo (vacío = gráfico activo)
input int      Inp_BarsToAnalyze   = 40000;       // Barras M5 a analizar
input int      Inp_ATR_Period      = 14;          // Período ATR
input int      Inp_ADX_Period      = 14;          // Período ADX

input group "=== SESIÓN OPERATIVA (servidor UTC+2) ==="
input int      Inp_SessWinter_H    = 16;          // Hora inicio sesión invierno (srv)
input int      Inp_SessWinter_M    = 35;          // Minuto inicio sesión invierno
input int      Inp_SessSummer_H    = 15;          // Hora inicio sesión verano (srv)
input int      Inp_SessSummer_M    = 35;          // Minuto inicio sesión verano
input int      Inp_SessDurationMin = 90;          // Duración sesión en minutos

input group "=== FILTRO IN-SAMPLE ==="
input bool     Inp_UseIS           = true;        // Filtrar solo período IS
input datetime Inp_IS_Start        = D'2021.01.01 00:00'; // IS inicio
input datetime Inp_IS_End          = D'2023.12.31 23:59'; // IS fin

input group "=== OUTPUT ==="
input string   Inp_OutputFile      = "CascadeGate_SPX500_Calibrator.csv";
input int      Inp_ForwardBars     = 12;          // Barras futuras para calcular WR aprox
input int      Inp_NumBuckets      = 10;          // Número de buckets para análisis WR

//─── MAIN ──────────────────────────────────────────────────────────────────────

void OnStart()
{
    string sym = (Inp_Symbol == "") ? Symbol() : Inp_Symbol;

    Print("╔══════════════════════════════════════════════════╗");
    Print("║   CascadeGate SPX500 — Calibrador v1.00          ║");
    Print("╚══════════════════════════════════════════════════╝");
    PrintFormat("Símbolo: %s | ATR(%d) | ADX(%d)", sym, Inp_ATR_Period, Inp_ADX_Period);
    if(Inp_UseIS)
        PrintFormat("Período IS: %s → %s", TimeToString(Inp_IS_Start), TimeToString(Inp_IS_End));
    else
        Print("Período: COMPLETO (sin filtro IS)");

    //── Crear handles ──────────────────────────────────────────────────────────
    int atrH = iATR(sym, PERIOD_M5, Inp_ATR_Period);
    int adxH = iADX(sym, PERIOD_M5, Inp_ADX_Period);

    if(atrH == INVALID_HANDLE || adxH == INVALID_HANDLE)
    {
        Print("ERROR CRÍTICO: No se pudieron crear los handles de indicadores");
        Print("Verificar que el símbolo existe y tiene datos M5 disponibles");
        return;
    }

    Sleep(3000); // Esperar inicialización de indicadores

    //── Cargar datos ───────────────────────────────────────────────────────────
    int totalBars = iBars(sym, PERIOD_M5);
    int barsToUse = MathMin(Inp_BarsToAnalyze, totalBars - Inp_ForwardBars - 5);

    if(barsToUse < 500)
    {
        PrintFormat("ERROR: Solo %d barras disponibles. Se necesitan al menos 500.", totalBars);
        IndicatorRelease(atrH);
        IndicatorRelease(adxH);
        return;
    }

    PrintFormat("Cargando %d barras M5...", barsToUse);

    double atrBuf[], adxBuf[];
    MqlRates rates[];
    ArraySetAsSeries(atrBuf, true);
    ArraySetAsSeries(adxBuf, true);
    ArraySetAsSeries(rates, true);

    int copied = CopyBuffer(atrH, 0, 0, barsToUse, atrBuf);
    if(copied <= 0) { Print("ERROR al copiar ATR buffer"); return; }

    copied = CopyBuffer(adxH, 0, 0, barsToUse, adxBuf);
    if(copied <= 0) { Print("ERROR al copiar ADX buffer"); return; }

    copied = (int)CopyRates(sym, PERIOD_M5, 0, barsToUse + Inp_ForwardBars, rates);
    if(copied <= 0) { Print("ERROR al copiar rates"); return; }

    PrintFormat("Datos cargados: %d barras", barsToUse);

    //── Filtrar barras de sesión ────────────────────────────────────────────────
    double atrSess[], adxSess[];
    bool   dirBull[];   // WR aproximado: ¿precio subió más de lo que bajó?

    ArrayResize(atrSess, barsToUse);
    ArrayResize(adxSess, barsToUse);
    ArrayResize(dirBull, barsToUse);

    int sessCount = 0;

    for(int i = 1; i < barsToUse; i++)
    {
        datetime barTime = rates[i].time;

        // Filtro IS
        if(Inp_UseIS && (barTime < Inp_IS_Start || barTime > Inp_IS_End)) continue;

        // Filtro de sesión
        MqlDateTime dt;
        TimeToStruct(barTime, dt);
        bool isEDT = IsEdtPeriod(dt);
        int sessH = isEDT ? Inp_SessSummer_H : Inp_SessWinter_H;
        int sessM = isEDT ? Inp_SessSummer_M : Inp_SessWinter_M;
        int barMins   = dt.hour * 60 + dt.min;
        int startMins = sessH  * 60 + sessM;

        if(barMins < startMins || barMins >= startMins + Inp_SessDurationMin) continue;
        if(atrBuf[i] <= 0 || adxBuf[i] <= 0) continue;

        // WR aproximado: max upside vs max downside en siguientes ForwardBars velas
        double entry    = rates[i].close;
        double maxUp    = 0;
        double maxDown  = 0;
        for(int j = i - 1; j >= MathMax(0, i - Inp_ForwardBars); j--)
        {
            maxUp   = MathMax(maxUp,   rates[j].high - entry);
            maxDown = MathMax(maxDown, entry - rates[j].low);
        }
        bool bullResult = (maxUp > maxDown);

        atrSess[sessCount] = atrBuf[i];
        adxSess[sessCount] = adxBuf[i];
        dirBull[sessCount] = bullResult;
        sessCount++;
    }

    PrintFormat("Barras de sesión válidas: %d", sessCount);

    if(sessCount < 200)
    {
        Print("ERROR: Muestra insuficiente (<200 barras de sesión). Ampliar rango de análisis.");
        IndicatorRelease(atrH); IndicatorRelease(adxH);
        return;
    }

    //── Calcular percentiles ATR ────────────────────────────────────────────────
    double atrSort[];
    ArrayResize(atrSort, sessCount);
    ArrayCopy(atrSort, atrSess, 0, 0, sessCount);
    ArraySort(atrSort);

    double atrP05  = Percentile(atrSort, sessCount, 5);
    double atrP10  = Percentile(atrSort, sessCount, 10);
    double atrP25  = Percentile(atrSort, sessCount, 25);
    double atrP35  = Percentile(atrSort, sessCount, 35);
    double atrP50  = Percentile(atrSort, sessCount, 50);
    double atrP65  = Percentile(atrSort, sessCount, 65);
    double atrP75  = Percentile(atrSort, sessCount, 75);
    double atrP90  = Percentile(atrSort, sessCount, 90);
    double atrP95  = Percentile(atrSort, sessCount, 95);
    double atrMean = ArrayMean(atrSess, sessCount);

    //── Calcular percentiles ADX ────────────────────────────────────────────────
    double adxSort[];
    ArrayResize(adxSort, sessCount);
    ArrayCopy(adxSort, adxSess, 0, 0, sessCount);
    ArraySort(adxSort);

    double adxP20  = Percentile(adxSort, sessCount, 20);
    double adxP30  = Percentile(adxSort, sessCount, 30);
    double adxP38  = Percentile(adxSort, sessCount, 38);
    double adxP50  = Percentile(adxSort, sessCount, 50);
    double adxP55  = Percentile(adxSort, sessCount, 55);
    double adxP70  = Percentile(adxSort, sessCount, 70);
    double adxMean = ArrayMean(adxSess, sessCount);

    //── Análisis WR por bucket ATR ──────────────────────────────────────────────
    int    atrBucketN[], atrBucketW[];
    double atrBucketMins[], atrBucketMaxs[];
    ArrayResize(atrBucketN, Inp_NumBuckets); ArrayInitialize(atrBucketN, 0);
    ArrayResize(atrBucketW, Inp_NumBuckets); ArrayInitialize(atrBucketW, 0);
    ArrayResize(atrBucketMins, Inp_NumBuckets);
    ArrayResize(atrBucketMaxs, Inp_NumBuckets);

    double atrRange = atrSort[sessCount-1] - atrSort[0];
    double atrStep  = atrRange / Inp_NumBuckets;
    for(int i = 0; i < Inp_NumBuckets; i++)
    {
        atrBucketMins[i] = atrSort[0] + i * atrStep;
        atrBucketMaxs[i] = atrBucketMins[i] + atrStep;
    }

    for(int i = 0; i < sessCount; i++)
    {
        int b = (int)((atrSess[i] - atrSort[0]) / atrStep);
        b = MathMin(b, Inp_NumBuckets - 1);
        atrBucketN[b]++;
        if(dirBull[i]) atrBucketW[b]++;
    }

    //── Análisis WR por bucket ADX ──────────────────────────────────────────────
    int    adxBucketN[], adxBucketW[];
    double adxBucketMins[], adxBucketMaxs[];
    ArrayResize(adxBucketN, Inp_NumBuckets); ArrayInitialize(adxBucketN, 0);
    ArrayResize(adxBucketW, Inp_NumBuckets); ArrayInitialize(adxBucketW, 0);
    ArrayResize(adxBucketMins, Inp_NumBuckets);
    ArrayResize(adxBucketMaxs, Inp_NumBuckets);

    double adxRange = adxSort[sessCount-1] - adxSort[0];
    double adxStep  = adxRange / Inp_NumBuckets;
    for(int i = 0; i < Inp_NumBuckets; i++)
    {
        adxBucketMins[i] = adxSort[0] + i * adxStep;
        adxBucketMaxs[i] = adxBucketMins[i] + adxStep;
    }

    for(int i = 0; i < sessCount; i++)
    {
        int b = (int)((adxSess[i] - adxSort[0]) / adxStep);
        b = MathMin(b, Inp_NumBuckets - 1);
        adxBucketN[b]++;
        if(dirBull[i]) adxBucketW[b]++;
    }

    //── Análisis combinado ATR×ADX (búsqueda de combo tóxico) ──────────────────
    // Grid 4×4 de rangos ATR × ADX
    int    gridN[4][4];
    int    gridW[4][4];
    double atrGridStep = atrRange / 4.0;
    double adxGridStep = adxRange / 4.0;
    for(int i = 0; i < 4; i++) for(int j = 0; j < 4; j++) { gridN[i][j]=0; gridW[i][j]=0; }

    for(int i = 0; i < sessCount; i++)
    {
        int ia = (int)((atrSess[i] - atrSort[0]) / atrGridStep);
        int ja = (int)((adxSess[i] - adxSort[0]) / adxGridStep);
        ia = MathMin(ia, 3); ja = MathMin(ja, 3);
        gridN[ia][ja]++;
        if(dirBull[i]) gridW[ia][ja]++;
    }

    //── IMPRIMIR RESULTADOS EN DIARIO ───────────────────────────────────────────
    Print(""); Print("───────────────────────────────────────────────────");
    Print("    PERCENTILES ATR(14) — SESIÓN OPERATIVA");
    Print("───────────────────────────────────────────────────");
    PrintFormat("  P05  = %.4f  → ATR_MinPrice (punto de partida)", atrP05);
    PrintFormat("  P10  = %.4f", atrP10);
    PrintFormat("  P25  = %.4f", atrP25);
    PrintFormat("  P35  = %.4f  → ATR_DeadZone_Min (VERIFICAR con BT)", atrP35);
    PrintFormat("  P50  = %.4f  → ATR_DeadZone_Max (VERIFICAR con BT)", atrP50);
    PrintFormat("  P65  = %.4f", atrP65);
    PrintFormat("  P75  = %.4f", atrP75);
    PrintFormat("  P90  = %.4f", atrP90);
    PrintFormat("  P95  = %.4f  → ATR_MaxPrice (punto de partida)", atrP95);
    PrintFormat("  Media= %.4f", atrMean);

    Print(""); Print("───────────────────────────────────────────────────");
    Print("    PERCENTILES ADX(14) — SESIÓN OPERATIVA");
    Print("───────────────────────────────────────────────────");
    PrintFormat("  P20  = %.2f", adxP20);
    PrintFormat("  P30  = %.2f", adxP30);
    PrintFormat("  P38  = %.2f  → ADX_MinLevel (equivalente al P38 de NAS100)", adxP38);
    PrintFormat("  P50  = %.2f", adxP50);
    PrintFormat("  P55  = %.2f", adxP55);
    PrintFormat("  P70  = %.2f", adxP70);
    PrintFormat("  Media= %.2f", adxMean);

    Print(""); Print("───────────────────────────────────────────────────");
    Print("    PARÁMETROS INICIALES RECOMENDADOS PARA EA");
    Print("───────────────────────────────────────────────────");
    PrintFormat("  Inp_ATR_MinPrice        = %.2f  (P05)", atrP05);
    PrintFormat("  Inp_ATR_MaxPrice        = %.2f  (P95)", atrP95);
    PrintFormat("  Inp_ATR_DZ_Min          = %.2f  (P35 — PENDIENTE VERIFICACIÓN BT)", atrP35);
    PrintFormat("  Inp_ATR_DZ_Max          = %.2f  (P50 — PENDIENTE VERIFICACIÓN BT)", atrP50);
    PrintFormat("  Inp_ADX_MinLevel        = %.1f  (P38)", adxP38);
    PrintFormat("  Inp_FVG_MaxDistPrice    = %.2f  (ATR_MaxPrice × 1.35)", atrP95 * 1.35);
    PrintFormat("  Inp_FVG_MinSizePrice    = %.3f  (ATR_P05 × 0.5 — estimado, validar)", atrP05 * 0.5);
    Print("  Inp_ADX_DZ_Min/Max       = 33.0 / 41.0  (mismo que NAS100, verificar)");
    Print("  Inp_ADX_Cond_Min/Max     = 28.0 / 32.0  (ídem, verificar)");
    Print("  Inp_ATR_CondMin/Max      = PENDIENTE (buscar en grid ATR×ADX)");

    Print(""); Print("───────────────────────────────────────────────────");
    Print("    WR APROXIMADO POR BUCKET ATR");
    Print("    (WR relativo — no es WR con SL/TP real)");
    Print("───────────────────────────────────────────────────");
    for(int i = 0; i < Inp_NumBuckets; i++)
    {
        double wr = (atrBucketN[i] > 0) ? (100.0 * atrBucketW[i] / atrBucketN[i]) : -1;
        string alert = "";
        if(wr < 45 && atrBucketN[i] >= 30) alert = "  ⚠ POSIBLE DEAD ZONE";
        if(wr < 0) alert = "  (sin datos)";
        PrintFormat("  [%.3f – %.3f]: n=%d | WR=%.1f%%%s",
                    atrBucketMins[i], atrBucketMaxs[i], atrBucketN[i], MathMax(wr,0), alert);
    }

    Print(""); Print("───────────────────────────────────────────────────");
    Print("    WR APROXIMADO POR BUCKET ADX");
    Print("───────────────────────────────────────────────────");
    for(int i = 0; i < Inp_NumBuckets; i++)
    {
        double wr = (adxBucketN[i] > 0) ? (100.0 * adxBucketW[i] / adxBucketN[i]) : -1;
        string alert = "";
        if(wr < 45 && adxBucketN[i] >= 30) alert = "  ⚠ POSIBLE DEAD ZONE";
        if(wr < 0) alert = "  (sin datos)";
        PrintFormat("  [%.1f – %.1f]: n=%d | WR=%.1f%%%s",
                    adxBucketMins[i], adxBucketMaxs[i], adxBucketN[i], MathMax(wr,0), alert);
    }

    Print(""); Print("───────────────────────────────────────────────────");
    Print("    GRID WR COMBINADO ATR × ADX (4×4)");
    Print("    Buscar celdas con WR<45% y n>=20: combo tóxico candidato");
    Print("───────────────────────────────────────────────────");
    for(int j = 3; j >= 0; j--)
    {
        string row = StringFormat("  ADX[%.0f-%.0f] |",
                                  adxSort[0]+j*adxGridStep,
                                  adxSort[0]+(j+1)*adxGridStep);
        for(int i = 0; i < 4; i++)
        {
            double wr = (gridN[i][j] > 0) ? (100.0*gridW[i][j]/gridN[i][j]) : -1;
            row += StringFormat(" %.0f%%(%d) |", MathMax(wr,0), gridN[i][j]);
        }
        Print(row);
    }
    PrintFormat("  ATR cuadrantes: [%.2f-%.2f] | [%.2f-%.2f] | [%.2f-%.2f] | [%.2f-%.2f]",
                atrSort[0], atrSort[0]+atrGridStep,
                atrSort[0]+atrGridStep, atrSort[0]+2*atrGridStep,
                atrSort[0]+2*atrGridStep, atrSort[0]+3*atrGridStep,
                atrSort[0]+3*atrGridStep, atrSort[sessCount-1]);

    //── ESCRIBIR CSV ────────────────────────────────────────────────────────────
    int fh = FileOpen(Inp_OutputFile, FILE_WRITE | FILE_CSV | FILE_COMMON, ',');
    if(fh == INVALID_HANDLE)
    {
        Print("ERROR: No se pudo crear el archivo CSV");
    }
    else
    {
        // Header info
        FileWrite(fh, "CascadeGate SPX500 Calibrador v1.00");
        FileWrite(fh, "Símbolo", sym);
        FileWrite(fh, "Período IS", Inp_UseIS ? TimeToString(Inp_IS_Start)+" → "+TimeToString(Inp_IS_End) : "COMPLETO");
        FileWrite(fh, "Barras sesión analizadas", sessCount);
        FileWrite(fh, "");

        // ATR percentiles
        FileWrite(fh, "SECCIÓN 1: PERCENTILES ATR");
        FileWrite(fh, "Percentil", "Valor", "Uso en EA");
        FileWrite(fh, "P05",  DoubleToString(atrP05,4), "ATR_MinPrice (punto de partida)");
        FileWrite(fh, "P10",  DoubleToString(atrP10,4), "");
        FileWrite(fh, "P25",  DoubleToString(atrP25,4), "");
        FileWrite(fh, "P35",  DoubleToString(atrP35,4), "ATR_DZ_Min (verificar con BT)");
        FileWrite(fh, "P50",  DoubleToString(atrP50,4), "ATR_DZ_Max (verificar con BT)");
        FileWrite(fh, "P65",  DoubleToString(atrP65,4), "");
        FileWrite(fh, "P75",  DoubleToString(atrP75,4), "");
        FileWrite(fh, "P90",  DoubleToString(atrP90,4), "");
        FileWrite(fh, "P95",  DoubleToString(atrP95,4), "ATR_MaxPrice (punto de partida)");
        FileWrite(fh, "Media",DoubleToString(atrMean,4),"");
        FileWrite(fh, "");

        // ADX percentiles
        FileWrite(fh, "SECCIÓN 2: PERCENTILES ADX");
        FileWrite(fh, "Percentil", "Valor", "Uso en EA");
        FileWrite(fh, "P20",  DoubleToString(adxP20,2), "");
        FileWrite(fh, "P30",  DoubleToString(adxP30,2), "");
        FileWrite(fh, "P38",  DoubleToString(adxP38,2), "ADX_MinLevel");
        FileWrite(fh, "P50",  DoubleToString(adxP50,2), "");
        FileWrite(fh, "P55",  DoubleToString(adxP55,2), "");
        FileWrite(fh, "P70",  DoubleToString(adxP70,2), "");
        FileWrite(fh, "Media",DoubleToString(adxMean,2),"");
        FileWrite(fh, "");

        // Parámetros recomendados
        FileWrite(fh, "SECCIÓN 3: PARÁMETROS INICIALES PARA EA (CALIBRAR LUEGO CON BT)");
        FileWrite(fh, "Parámetro", "Valor Inicial", "Rango Optimización IS");
        FileWrite(fh, "Inp_ATR_MinPrice",     DoubleToString(atrP05,2),        StringFormat("%.2f – %.2f", atrP05*0.8, atrP05*1.5));
        FileWrite(fh, "Inp_ATR_MaxPrice",     DoubleToString(atrP95,2),        StringFormat("%.2f – %.2f", atrP95*0.85, atrP95*1.1));
