            string alerta = "";
            if(wr < 45 && adxBucketN[i] >= 30) alerta = "POSIBLE DEAD ZONE";
            FileWrite(fh, i+1,
                      DoubleToString(adxBucketMins[i],1),
                      DoubleToString(adxBucketMaxs[i],1),
                      adxBucketN[i],
                      DoubleToString(wr,1),
                      alerta);
        }
        FileWrite(fh, "");

        // Grid combinado
        FileWrite(fh, "SECCIÓN 6: GRID WR COMBINADO ATR x ADX (buscar combos tóxicos WR<45%, n>=20)");
        string headerRow = "ADX\\ATR";
        for(int i = 0; i < 4; i++)
            headerRow += StringFormat(",ATR[%.2f-%.2f]", atrSort[0]+i*atrGridStep, atrSort[0]+(i+1)*atrGridStep);
        FileWrite(fh, headerRow);
        for(int j = 3; j >= 0; j--)
        {
            string row = StringFormat("ADX[%.1f-%.1f]", adxSort[0]+j*adxGridStep, adxSort[0]+(j+1)*adxGridStep);
            for(int i = 0; i < 4; i++)
            {
                double wr = (gridN[i][j] > 0) ? (100.0*gridW[i][j]/gridN[i][j]) : -1;
                row += StringFormat(",%.1f%%(n=%d)", MathMax(wr,0), gridN[i][j]);
            }
