//─── HELPERS ───────────────────────────────────────────────────────────────────

double Percentile(const double &sortedArr[], int n, int pct)
{
    int idx = (int)MathRound(n * pct / 100.0);
    idx = MathMax(0, MathMin(n - 1, idx));
    return sortedArr[idx];
}

double ArrayMean(const double &arr[], int n)
{
    double sum = 0;
    for(int i = 0; i < n; i++) sum += arr[i];
    return (n > 0) ? sum / n : 0;
}

bool IsEdtPeriod(const MqlDateTime &dt)
{
    int m = dt.mon;
    if(m > 3 && m < 11) return true;
    if(m < 3 || m > 11) return false;
    if(m == 3)
    {
        // Después del segundo domingo de marzo
        MqlDateTime tmp; tmp.year=dt.year; tmp.mon=3; tmp.day=1; tmp.hour=0; tmp.min=0; tmp.sec=0;
        datetime d = StructToTime(tmp);
        int dow = (int)((d / 86400 + 4) % 7);
        int firstSun = (dow == 0) ? 1 : 8 - dow;
        int secondSun = firstSun + 7;
        return (dt.day >= secondSun);
    }
    if(m == 11)
    {
        MqlDateTime tmp; tmp.year=dt.year; tmp.mon=11; tmp.day=1; tmp.hour=0; tmp.min=0; tmp.sec=0;
        datetime d = StructToTime(tmp);
        int dow = (int)((d / 86400 + 4) % 7);
        int firstSun = (dow == 0) ? 1 : 8 - dow;
        return (dt.day < firstSun);
    }
    return false;
}
