input group "═══ ADX — F1/F1b/F1c (CALIBRAR percentiles en IS) ═══"
input double Inp_ADX_MinLevel      = 22.0;    // F1: ADX mínimo [P38 IS; punto de partida]
input bool   Inp_ADX_DZ_Enable     = true;    // F1b: Dead zone ADX activa
input double Inp_ADX_DZ_Min        = 33.0;    // F1b: DZ mínimo [verificar en IS]
input double Inp_ADX_DZ_Max        = 41.0;    // F1b: DZ máximo [verificar en IS]
input bool   Inp_ADX_DZ2_Enable    = false;   // F1c: Dead zone ADX 2 (OFF — evidencia insuficiente)
input double Inp_ADX_DZ2_Min       = 25.0;    // F1c: DZ2 mínimo
input double Inp_ADX_DZ2_Max       = 27.0;    // F1c: DZ2 máximo

input group "═══ COMBO TÓXICO ATR+ADX — F1d (CALIBRAR en IS) ═══"
input bool   Inp_ADX_Cond_Enable   = true;    // F1d: Filtro combo tóxico
input double Inp_ATR_CondMin       = 8.0;     // F1d: ATR rango mín [ESTIMADO — calibrar]
input double Inp_ATR_CondMax       = 12.0;    // F1d: ATR rango máx [ESTIMADO — calibrar]
input double Inp_ADX_CondMin       = 28.0;    // F1d: ADX rango mín [punto de partida]
input double Inp_ADX_CondMax       = 32.0;    // F1d: ADX rango máx [punto de partida]

input group "═══ ATR VOLATILIDAD — F5/F5b (⚠ CALIBRAR con script) ═══"
input double Inp_ATR_MinPrice      = 3.0;     // F5: ATR mínimo precio [P05 — ESTIMADO]
input double Inp_ATR_MaxPrice      = 22.0;    // F5: ATR máximo precio [P95 — ESTIMADO]
input bool   Inp_ATR_DZ_Enable     = true;    // F5b: Dead zone ATR activa
input double Inp_ATR_DZ_Min        = 10.0;    // F5b: ATR DZ mínimo [P35 — ESTIMADO]
input double Inp_ATR_DZ_Max        = 15.0;    // F5b: ATR DZ máximo [P50 — ESTIMADO]

input group "═══ FVG — F6 (⚠ CALIBRAR con script) ═══"
input double Inp_FVG_MinSizePrice  = 1.5;     // F6: Tamaño mínimo FVG [ESTIMADO]
input double Inp_FVG_MaxDistPrice  = 30.0;    // F6: Distancia máx precio-FVG [ATR_Max×1.35]
input int    Inp_FVG_LookbackBars  = 30;      // F6: Velas lookback para buscar FVG

input group "═══ VELA DE ENTRADA — F7/F7c ═══"
input int    Inp_ConsecBullish     = 1;       // F7: Mínimo velas alcistas consecutivas (INVARIANT)
input double Inp_BodyRatioPct      = 0.25;    // F7c: Cuerpo mínimo como % del ATR (INVARIANT)

input group "═══ RIESGO — INVARIANTES (no modificar sin evidencia) ═══"
input double Inp_RiskPercent       = 1.0;     // Riesgo % del balance por trade
