input int    Inp_BE_Candles        = 20;      // Velas M5 antes de evaluar BE (INVARIANT)
input double Inp_BE_MinR           = 0.30;    // Float mínimo en R para activar BE (INVARIANT)

input group "═══ COOLDOWN Y RACHA — INVARIANTES ═══"
