int OnInit()
{
    _sym    = (Inp_Symbol == "") ? Symbol() : Inp_Symbol;
    _digits = (int)SymbolInfoInteger(_sym, SYMBOL_DIGITS);

    //── Crear handles ──────────────────────────────────────────────────────────
    _hATR    = iATR(_sym, PERIOD_M5, 14);
    _hADX    = iADX(_sym, PERIOD_M5, 14);
    _hEMA9   = iMA(_sym, PERIOD_M5,   9, 0, MODE_EMA, PRICE_CLOSE);
    _hEMA21  = iMA(_sym, PERIOD_M5,  21, 0, MODE_EMA, PRICE_CLOSE);
    _hEMA50  = iMA(_sym, PERIOD_M5,  50, 0, MODE_EMA, PRICE_CLOSE);
    _hEMA200 = iMA(_sym, PERIOD_M5, 200, 0, MODE_EMA, PRICE_CLOSE);
    _hEMA50_H1 = iMA(_sym, PERIOD_H1, 50, 0, MODE_EMA, PRICE_CLOSE);
    _hMACD   = iMACD(_sym, PERIOD_M5, 12, 26, 9, PRICE_CLOSE);

    if(_hATR==INVALID_HANDLE || _hADX==INVALID_HANDLE ||
       _hEMA9==INVALID_HANDLE || _hEMA21==INVALID_HANDLE ||
       _hEMA50==INVALID_HANDLE || _hEMA200==INVALID_HANDLE ||
       _hEMA50_H1==INVALID_HANDLE || _hMACD==INVALID_HANDLE)
    {
        Print("INIT ERROR: Fallo al crear handles de indicadores");
        return INIT_FAILED;
    }

    //── Configurar objeto Trade ─────────────────────────────────────────────────
    Trade.SetExpertMagicNumber(Inp_MagicNumber);
    Trade.SetDeviationInPoints(50);
    Trade.SetTypeFilling(ORDER_FILLING_IOC);
    Trade.LogLevel(LOG_LEVEL_ERRORS);

    //── Inicializar CSV ─────────────────────────────────────────────────────────
    InitCSV();

    //── Log de inicio ───────────────────────────────────────────────────────────
    Print("╔══════════════════════════════════════════════════════════════╗");
    Print("║          CascadeGate SPX500 v1.00 — FundingPips             ║");
    Print("╚══════════════════════════════════════════════════════════════╝");
    PrintFormat("Símbolo   : %s | Dígitos: %d | Magic: %d", _sym, _digits, Inp_MagicNumber);
    PrintFormat("Sesión    : %02d:%02d (inv) / %02d:%02d (ver) UTC+2 → %d min",
                Inp_SessWinter_H, Inp_SessWinter_M,
                Inp_SessSummer_H, Inp_SessSummer_M,
                Inp_SessDurationMin);
    PrintFormat("ATR range : [%.2f, %.2f] | DZ: [%.2f, %.2f]",
                Inp_ATR_MinPrice, Inp_ATR_MaxPrice, Inp_ATR_DZ_Min, Inp_ATR_DZ_Max);
    PrintFormat("ADX min   : %.1f | DZ: [%.1f, %.1f] | F1d cond: %s",
                Inp_ADX_MinLevel, Inp_ADX_DZ_Min, Inp_ADX_DZ_Max,
                Inp_ADX_Cond_Enable ? "ON" : "OFF");
    PrintFormat("FVG       : min=%.3f | maxDist=%.2f | lookback=%d velas",
                Inp_FVG_MinSizePrice, Inp_FVG_MaxDistPrice, Inp_FVG_LookbackBars);
    PrintFormat("Riesgo    : %.1f%% | SL×%.2f | TP×%.2f | MaxDay=%d",
                Inp_RiskPercent, Inp_SL_ATR_Mult, Inp_TP_ATR_Mult, Inp_MaxTradesDay);
    if(Inp_ATR_MinPrice < 2.0 || Inp_ATR_MaxPrice > 50.0)
        Print("⚠ ADVERTENCIA: Parámetros ATR fuera de rango esperado para SPX500 — calibrar primero");
    Print("─────────────────────────────────────────────────────────────────");

    return INIT_SUCCEEDED;
}

void OnDeinit(const int reason)
{
    if(_csvHandle != INVALID_HANDLE) { FileClose(_csvHandle); _csvHandle = INVALID_HANDLE; }
    IndicatorRelease(_hATR);    IndicatorRelease(_hADX);
    IndicatorRelease(_hEMA9);   IndicatorRelease(_hEMA21);
    IndicatorRelease(_hEMA50);  IndicatorRelease(_hEMA200);
    IndicatorRelease(_hEMA50_H1); IndicatorRelease(_hMACD);
}

//══════════════════════════════════════════════════════════════════════════════
//  ONTICK — LÓGICA PRINCIPAL
//══════════════════════════════════════════════════════════════════════════════

void OnTick()
{
    // Procesar solo en barra M5 nueva (evita re-evaluación en el mismo cierre)
    datetime barTime = iTime(_sym, PERIOD_M5, 0);
    if(barTime == _lastBarTime) return;
    _lastBarTime = barTime;

    // Actualizar contador diario
    UpdateDailyCounter();

    // Si hay posición abierta → gestionar breakeven, no abrir nuevas
    if(HasOpenPosition())
    {
        ManageBreakeven();
        return;
    }

    // Verificar ventana de sesión
    if(!IsInSession()) return;

    // Verificar límite de trades diarios
    if(_tradesToday >= Inp_MaxTradesDay) return;

    // Verificar pausa de racha
    if(_streakPauseEnd > 0 && TimeCurrent() < _streakPauseEnd) return;

    // Verificar cooldown post-loss
    if(Inp_LossCooldown && _lastLossTime > 0)
        if(TimeCurrent() - _lastLossTime < (long)Inp_LossCD_Min * 60) return;

    // Ejecutar cascada de 12 filtros
    EvaluateAndTrade();
}

//══════════════════════════════════════════════════════════════════════════════
//  GESTIÓN DE SESIÓN
//══════════════════════════════════════════════════════════════════════════════

bool IsInSession()
{
    MqlDateTime dt;
    TimeToStruct(TimeCurrent(), dt);

    bool edt = (Inp_AutoDST) ? IsEdtPeriod(dt) : false;
    int sh = edt ? Inp_SessSummer_H : Inp_SessWinter_H;
    int sm = edt ? Inp_SessSummer_M : Inp_SessWinter_M;

    int nowMin   = dt.hour * 60 + dt.min;
    int startMin = sh * 60 + sm;
    int endMin   = startMin + Inp_SessDurationMin;

    return (nowMin >= startMin && nowMin < endMin);
}

bool IsEdtPeriod(const MqlDateTime &dt)
{
    int m = dt.mon;
    if(m > 3 && m < 11) return true;
    if(m < 3 || m > 11) return false;

    MqlDateTime tmp;
    tmp.year = dt.year; tmp.hour = 0; tmp.min = 0; tmp.sec = 0;
    if(m == 3)
    {
        tmp.mon = 3; tmp.day = 1;
        datetime d = StructToTime(tmp);
        int dow = (int)((d / 86400 + 4) % 7); // 0=Dom
        int firstSun  = (dow == 0) ? 1 : 8 - dow;
        int secondSun = firstSun + 7;
        return (dt.day >= secondSun);
    }
    // m == 11
    tmp.mon = 11; tmp.day = 1;
    datetime d = StructToTime(tmp);
    int dow = (int)((d / 86400 + 4) % 7);
    int firstSun = (dow == 0) ? 1 : 8 - dow;
    return (dt.day < firstSun);
}

//══════════════════════════════════════════════════════════════════════════════
//  CASCADA DE 12 FILTROS
//══════════════════════════════════════════════════════════════════════════════

void EvaluateAndTrade()
{
    //── Obtener datos de barras ─────────────────────────────────────────────────
    int lookback = MathMax(Inp_FVG_LookbackBars + 5, 210);

    MqlRates rates[];
    ArraySetAsSeries(rates, true);
    if(CopyRates(_sym, PERIOD_M5, 1, lookback, rates) < lookback) return;

    double atrBuf[], adxBuf[];
    double ema9[], ema21[], ema50[], ema200[];
    double ema50H1[];
    double macdHist[];

    ArraySetAsSeries(atrBuf, true);  ArraySetAsSeries(adxBuf,  true);
    ArraySetAsSeries(ema9, true);    ArraySetAsSeries(ema21,   true);
    ArraySetAsSeries(ema50, true);   ArraySetAsSeries(ema200,  true);
    ArraySetAsSeries(ema50H1, true); ArraySetAsSeries(macdHist, true);

    if(CopyBuffer(_hATR, 0, 1, lookback, atrBuf)  <= 0) return;
    if(CopyBuffer(_hADX, 0, 1, 1,        adxBuf)  <= 0) return;
    if(CopyBuffer(_hEMA9,   0, 1, 1,     ema9)    <= 0) return;
    if(CopyBuffer(_hEMA21,  0, 1, 1,     ema21)   <= 0) return;
    if(CopyBuffer(_hEMA50,  0, 1, 1,     ema50)   <= 0) return;
    if(CopyBuffer(_hEMA200, 0, 1, 1,     ema200)  <= 0) return;
    if(CopyBuffer(_hEMA50_H1, 0, 1, 1,   ema50H1) <= 0) return;
    if(CopyBuffer(_hMACD, 2, 1, 1,       macdHist)<= 0) return;  // Buffer 2 = Histograma

    double atrVal  = atrBuf[0];
    double adxVal  = adxBuf[0];
    double close   = rates[0].close;

    //══════════════════════════════════════════════════════════════════════════
    //  F0 — Filtro de día y hora
    //══════════════════════════════════════════════════════════════════════════
    MqlDateTime dt;
    TimeToStruct(TimeCurrent(), dt);

    if(Inp_AvoidWednesday && dt.day_of_week == 3)
    {
        if(Inp_VerboseLog) Print("F0: RECHAZADO — Miércoles (WR bajo esperado)");
        return;
    }

    if(Inp_AvoidFridayFirst && dt.day_of_week == 5)
    {
        bool edt = Inp_AutoDST ? IsEdtPeriod(dt) : false;
        int sh = edt ? Inp_SessSummer_H : Inp_SessWinter_H;
        int sm = edt ? Inp_SessSummer_M : Inp_SessWinter_M;
        int nowMin   = dt.hour * 60 + dt.min;
        int startMin = sh * 60 + sm;
        if(nowMin < startMin + 15)
        {
            if(Inp_VerboseLog) Print("F0: RECHAZADO — Viernes primera hora (WR bajo esperado)");
            return;
        }
    }

    //══════════════════════════════════════════════════════════════════════════
    //  F1 — ADX mínimo (momentum direccional mínimo requerido)
    //══════════════════════════════════════════════════════════════════════════
    if(adxVal < Inp_ADX_MinLevel)
    {
        if(Inp_VerboseLog) PrintFormat("F1: RECHAZADO — ADX=%.1f < %.1f (sin momentum)", adxVal, Inp_ADX_MinLevel);
        return;
    }

    //══════════════════════════════════════════════════════════════════════════
    //  F1b — Dead zone ADX [33, 41]: zona de transición inestable
    //══════════════════════════════════════════════════════════════════════════
    if(Inp_ADX_DZ_Enable && adxVal >= Inp_ADX_DZ_Min && adxVal <= Inp_ADX_DZ_Max)
    {
        if(Inp_VerboseLog) PrintFormat("F1b: RECHAZADO — ADX=%.1f en DZ [%.1f, %.1f]", adxVal, Inp_ADX_DZ_Min, Inp_ADX_DZ_Max);
        return;
    }

    //══════════════════════════════════════════════════════════════════════════
    //  F1c — Dead zone ADX 2 (OFF por defecto — muestra insuficiente)
    //══════════════════════════════════════════════════════════════════════════
    if(Inp_ADX_DZ2_Enable && adxVal >= Inp_ADX_DZ2_Min && adxVal <= Inp_ADX_DZ2_Max)
    {
        if(Inp_VerboseLog) PrintFormat("F1c: RECHAZADO — ADX=%.1f en DZ2 [%.1f, %.1f]", adxVal, Inp_ADX_DZ2_Min, Inp_ADX_DZ2_Max);
        return;
    }

    //══════════════════════════════════════════════════════════════════════════
    //  F1d — Combo tóxico ATR+ADX: zona de ruido sin dirección
    //  (Descubierto en NAS100 v3.0, confirmado v4.0 y v5.0 — verificar en SPX500)
    //══════════════════════════════════════════════════════════════════════════
    if(Inp_ADX_Cond_Enable &&
       atrVal >= Inp_ATR_CondMin && atrVal <= Inp_ATR_CondMax &&
       adxVal >= Inp_ADX_CondMin && adxVal <= Inp_ADX_CondMax)
    {
        if(Inp_VerboseLog) PrintFormat("F1d: RECHAZADO — Combo tóxico ATR=%.3f ADX=%.1f", atrVal, adxVal);
        return;
    }

    //══════════════════════════════════════════════════════════════════════════
    //  F2 — Alineación de EMAs en M5: tendencia alcista estructural
    //  EMA9 > EMA21 > EMA50 y Close > EMA200
    //══════════════════════════════════════════════════════════════════════════
    if(!(ema9[0] > ema21[0] && ema21[0] > ema50[0] && close > ema200[0]))
    {
        if(Inp_VerboseLog)
            PrintFormat("F2: RECHAZADO — EMAs no alineadas. EMA9=%.2f EMA21=%.2f EMA50=%.2f EMA200=%.2f Close=%.2f",
                        ema9[0], ema21[0], ema50[0], ema200[0], close);
        return;
    }

    //══════════════════════════════════════════════════════════════════════════
    //  F3 — Régimen H1: mercado en modo alcista macro
    //  Close > EMA50 en H1
    //══════════════════════════════════════════════════════════════════════════
    if(close <= ema50H1[0])
    {
        if(Inp_VerboseLog) PrintFormat("F3: RECHAZADO — Close=%.2f <= EMA50(H1)=%.2f", close, ema50H1[0]);
        return;
    }

    //══════════════════════════════════════════════════════════════════════════
    //  F4 — MACD histograma positivo: momentum confirmado
    //══════════════════════════════════════════════════════════════════════════
    if(macdHist[0] <= 0)
    {
        if(Inp_VerboseLog) PrintFormat("F4: RECHAZADO — MACD hist=%.5f <= 0", macdHist[0]);
        return;
    }

    //══════════════════════════════════════════════════════════════════════════
    //  F5 — Rango ATR: volatilidad dentro de rango operativo
    //  [ATR_MinPrice, ATR_MaxPrice] = P05 a P95 de la sesión
    //══════════════════════════════════════════════════════════════════════════
    if(atrVal < Inp_ATR_MinPrice || atrVal > Inp_ATR_MaxPrice)
    {
        if(Inp_VerboseLog)
            PrintFormat("F5: RECHAZADO — ATR=%.4f fuera de [%.4f, %.4f]", atrVal, Inp_ATR_MinPrice, Inp_ATR_MaxPrice);
        return;
    }

    //══════════════════════════════════════════════════════════════════════════
    //  F5b — Dead zone ATR: volatilidad media sin dirección clara
    //  [ATR_DZ_Min, ATR_DZ_Max] = P35 a P50 (verificar en IS)
    //══════════════════════════════════════════════════════════════════════════
    if(Inp_ATR_DZ_Enable && atrVal >= Inp_ATR_DZ_Min && atrVal <= Inp_ATR_DZ_Max)
    {
        if(Inp_VerboseLog) PrintFormat("F5b: RECHAZADO — ATR=%.4f en DZ [%.4f, %.4f]", atrVal, Inp_ATR_DZ_Min, Inp_ATR_DZ_Max);
        return;
    }

    //══════════════════════════════════════════════════════════════════════════
    //  F6 — FVG alcista presente: soporte estructural institucional
    //  Busca Fair Value Gap alcista en últimas FVG_LookbackBars velas M5
    //══════════════════════════════════════════════════════════════════════════
    double fvgLevel = 0;
    if(!FindBullishFVG(rates, Inp_FVG_LookbackBars, fvgLevel))
    {
        if(Inp_VerboseLog) Print("F6: RECHAZADO — Sin FVG alcista en lookback");
        return;
    }

    double distToFVG = close - fvgLevel;
    if(distToFVG < 0 || distToFVG > Inp_FVG_MaxDistPrice)
    {
        if(Inp_VerboseLog)
            PrintFormat("F6: RECHAZADO — Distancia al FVG=%.4f (límite %.4f) | FVG=%.4f Close=%.4f",
                        distToFVG, Inp_FVG_MaxDistPrice, fvgLevel, close);
        return;
    }

    //══════════════════════════════════════════════════════════════════════════
    //  F7 — Velas alcistas consecutivas: confirmación de momentum inmediato
    //══════════════════════════════════════════════════════════════════════════
    int bullCount = 0;
    for(int i = 0; i < Inp_ConsecBullish; i++)
    {
        if(rates[i].close > rates[i].open) bullCount++;
        else break;
    }
    if(bullCount < Inp_ConsecBullish)
    {
        if(Inp_VerboseLog) PrintFormat("F7: RECHAZADO — Solo %d/%d velas alcistas consecutivas", bullCount, Inp_ConsecBullish);
        return;
    }

    //══════════════════════════════════════════════════════════════════════════
    //  F7c — Cuerpo mínimo: filtra doji y velas de spread
    //  Cuerpo >= 25% del ATR
    //══════════════════════════════════════════════════════════════════════════
    double body    = rates[0].close - rates[0].open;
    double minBody = atrVal * Inp_BodyRatioPct;
    if(body < minBody)
    {
        if(Inp_VerboseLog)
            PrintFormat("F7c: RECHAZADO — Cuerpo=%.5f < mínimo=%.5f (%.0f%% del ATR)", body, minBody, Inp_BodyRatioPct*100);
        return;
    }

    //══════════════════════════════════════════════════════════════════════════
    //  ✓ TODOS LOS FILTROS SUPERADOS → EJECUTAR TRADE
    //══════════════════════════════════════════════════════════════════════════
    if(Inp_VerboseLog)
        PrintFormat("✓ SEÑAL VÁLIDA | ATR=%.4f | ADX=%.1f | FVG=%.4f | Dist=%.4f | Cuerpo=%.5f",
                    atrVal, adxVal, fvgLevel, distToFVG, body);

    _entryATR = atrVal;
    _entryADX = adxVal;
    _beActivated = false;
    ExecuteTrade(atrVal, adxVal);
}

//══════════════════════════════════════════════════════════════════════════════
//  DETECCIÓN FVG ALCISTA
//══════════════════════════════════════════════════════════════════════════════

bool FindBullishFVG(const MqlRates &rates[], int lookback, double &fvgMidpoint)
{
    // Un FVG alcista existe cuando:
    // rates[i+2].high < rates[i].low  (gap entre el máximo de 2 velas atrás y mínimo de vela actual)
    // El gap debe tener tamaño >= FVG_MinSizePrice
    // Se retorna el midpoint del gap como nivel de soporte FVG

    int maxIdx = MathMin(lookback - 1, ArraySize(rates) - 3);
    for(int i = 0; i <= maxIdx; i++)
    {
        double gapBottom = rates[i+2].high;  // Máximo de la vela más vieja del gap
        double gapTop    = rates[i].low;     // Mínimo de la vela más reciente

        if(gapTop > gapBottom)
        {
            double gapSize = gapTop - gapBottom;
            if(gapSize >= Inp_FVG_MinSizePrice)
            {
                fvgMidpoint = (gapTop + gapBottom) / 2.0;
                return true;
            }
        }
    }
    return false;
}

//══════════════════════════════════════════════════════════════════════════════
//  EJECUCIÓN DE TRADE
//══════════════════════════════════════════════════════════════════════════════

void ExecuteTrade(double atrVal, double adxVal)
{
    double ask       = SymbolInfoDouble(_sym, SYMBOL_ASK);
    double tickVal   = SymbolInfoDouble(_sym, SYMBOL_TRADE_TICK_VALUE);
    double tickSize  = SymbolInfoDouble(_sym, SYMBOL_TRADE_TICK_SIZE);
    double balance   = AccountInfoDouble(ACCOUNT_BALANCE);

    // Calcular SL y TP en puntos de precio
    double slPoints  = atrVal * Inp_SL_ATR_Mult;
    double tpPoints  = atrVal * Inp_TP_ATR_Mult;
    double slPrice   = NormalizeDouble(ask - slPoints, _digits);
    double tpPrice   = NormalizeDouble(ask + tpPoints, _digits);

    // Sizing: arriesgar exactamente RiskPercent% del balance
    double riskUSD   = balance * Inp_RiskPercent / 100.0;
    double slTicks   = slPoints / tickSize;
    double lotRaw    = riskUSD / (slTicks * tickVal);

    double lotMin    = SymbolInfoDouble(_sym, SYMBOL_VOLUME_MIN);
    double lotMax    = SymbolInfoDouble(_sym, SYMBOL_VOLUME_MAX);
    double lotStep   = SymbolInfoDouble(_sym, SYMBOL_VOLUME_STEP);
    double lot       = MathFloor(lotRaw / lotStep) * lotStep;
    lot = MathMax(lotMin, MathMin(lotMax, lot));

    if(lot <= 0)
    {
        Print("ERROR: Lote calculado <= 0. Verificar TickValue/TickSize del símbolo.");
        return;
    }

    // Comentario para recuperar ATR/ADX en el log
    string comment = StringFormat("CGS|ATR=%.4f|ADX=%.1f", atrVal, adxVal);

    if(Trade.Buy(lot, _sym, ask, slPrice, tpPrice, comment))
    {
        _tradesToday++;
        _lastEntryTime = TimeCurrent();
        _lastTicket    = Trade.ResultOrder();
        _beActivated   = false;
        PrintFormat("✓ BUY ABIERTO | Lot=%.2f | Entry=%.2f | SL=%.2f (%.4f pts) | TP=%.2f | RiesgoUSD=%.2f | ATR=%.4f | ADX=%.1f",
                    lot, ask, slPrice, slPoints, tpPrice, riskUSD, atrVal, adxVal);
    }
    else
    {
        PrintFormat("✗ ERROR Trade.Buy: %d — %s", GetLastError(), Trade.ResultRetcodeDescription());
    }
}

//══════════════════════════════════════════════════════════════════════════════
//  GESTIÓN DE BREAKEVEN
//══════════════════════════════════════════════════════════════════════════════

void ManageBreakeven()
{
    if(!Inp_BE_Enable) return;

    for(int i = PositionsTotal() - 1; i >= 0; i--)
    {
        if(!PosInfo.SelectByIndex(i)) continue;
        if(PosInfo.Magic()  != Inp_MagicNumber) continue;
        if(PosInfo.Symbol() != _sym) continue;

        double entryPx   = PosInfo.PriceOpen();
        double currentSL = PosInfo.StopLoss();
        double currentTP = PosInfo.TakeProfit();
        double bidPrice  = PosInfo.PriceCurrent();

        // Ya en BE o mejor
        if(currentSL >= entryPx - SymbolInfoDouble(_sym, SYMBOL_POINT)) continue;

        // Verificar velas transcurridas desde apertura
        datetime openTime    = (datetime)PosInfo.Time();
        long barsElapsed = (long)((TimeCurrent() - openTime) / 300);
        if(barsElapsed < Inp_BE_Candles) continue;

        // Verificar R flotante
        double slDist    = entryPx - currentSL;
        if(slDist <= 0) continue;
        double floatR    = (bidPrice - entryPx) / slDist;

        if(floatR >= Inp_BE_MinR)
        {
            double newSL = NormalizeDouble(entryPx, _digits);
            if(Trade.PositionModify(PosInfo.Ticket(), newSL, currentTP))
            {
                _beActivated = true;
                PrintFormat("✓ BREAKEVEN activado | Ticket=%d | SL → %.2f | FloatR=%.2fR | Velas=%d",
                            PosInfo.Ticket(), newSL, floatR, (int)barsElapsed);
            }
            else
            {
                PrintFormat("✗ ERROR al mover SL a BE: %d", GetLastError());
            }
        }
    }
}

//══════════════════════════════════════════════════════════════════════════════
//  EVENTOS DE TRANSACCIÓN (tracking de losses para cooldown y racha)
//══════════════════════════════════════════════════════════════════════════════

void OnTradeTransaction(const MqlTradeTransaction &trans,
                        const MqlTradeRequest      &request,
                        const MqlTradeResult       &result)
{
    if(trans.type != TRADE_TRANSACTION_DEAL_ADD) return;

    ulong dealTicket = trans.deal;
    if(!HistoryDealSelect(dealTicket)) return;

    long magic = HistoryDealGetInteger(dealTicket, DEAL_MAGIC);
    if(magic != Inp_MagicNumber) return;

    ENUM_DEAL_ENTRY entry = (ENUM_DEAL_ENTRY)HistoryDealGetInteger(dealTicket, DEAL_ENTRY);
    if(entry != DEAL_ENTRY_OUT) return;

    double profit   = HistoryDealGetDouble(dealTicket,  DEAL_PROFIT);
    double swap     = HistoryDealGetDouble(dealTicket,  DEAL_SWAP);
    double comision = HistoryDealGetDouble(dealTicket,  DEAL_COMMISSION);
    double netPnL   = profit + swap + comision;
    datetime closeT = (datetime)HistoryDealGetInteger(dealTicket, DEAL_TIME);
    double closeP   = HistoryDealGetDouble(dealTicket,  DEAL_PRICE);

    bool isLoss = (netPnL < 0);
    string resultado = isLoss ? "LOSS" : "WIN";

    PrintFormat("%s | Ticket=%d | NetPnL=%.2f | Profit=%.2f Swap=%.2f Com=%.2f",
                resultado, dealTicket, netPnL, profit, swap, comision);

    if(isLoss)
    {
        _lastLossTime = TimeCurrent();
        _consecLosses++;
        PrintFormat("LOSS #%d consecutivo", _consecLosses);

        if(Inp_StreakPause && _consecLosses >= Inp_MaxConsecLosses)
        {
            _streakPauseEnd = TimeCurrent() + 60 * 60;
            _consecLosses   = 0;
            PrintFormat("⚠ PAUSA DE RACHA: %d losses consecutivos → pausa hasta %s",
                        Inp_MaxConsecLosses, TimeToString(_streakPauseEnd));
        }
    }
    else
    {
        _consecLosses = 0;
    }

    // Recuperar info de apertura del deal opuesto
    ulong posID = HistoryDealGetInteger(dealTicket, DEAL_POSITION_ID);
    datetime openT    = 0;
    double   openP    = 0;
    string   openCmt  = "";

    if(HistorySelectByPosition(posID))
    {
        for(int d = HistoryDealsTotal() - 1; d >= 0; d--)
        {
            ulong dt = HistoryDealGetTicket(d);
            if(!HistoryDealSelect(dt)) continue;
            if(HistoryDealGetInteger(dt, DEAL_POSITION_ID) != (long)posID) continue;
            if((ENUM_DEAL_ENTRY)HistoryDealGetInteger(dt, DEAL_ENTRY) == DEAL_ENTRY_IN)
            {
                openT   = (datetime)HistoryDealGetInteger(dt, DEAL_TIME);
                openP   = HistoryDealGetDouble(dt, DEAL_PRICE);
                openCmt = HistoryDealGetString(dt, DEAL_COMMENT);
                break;
            }
        }
    }

    // Parsear ATR/ADX del comentario de apertura
    double atrEntry = 0, adxEntry = 0;
    int atrPos = StringFind(openCmt, "ATR=");
    if(atrPos >= 0) atrEntry = StringToDouble(StringSubstr(openCmt, atrPos+4, 8));
    int adxPos = StringFind(openCmt, "ADX=");
    if(adxPos >= 0) adxEntry = StringToDouble(StringSubstr(openCmt, adxPos+4, 6));

    long durMin = (openT > 0) ? (long)(closeT - openT) / 60 : 0;
    double balPost = AccountInfoDouble(ACCOUNT_BALANCE);
    double balPre  = balPost - netPnL;

    LogTrade(dealTicket, posID, openT, closeT, openP, closeP, netPnL, resultado,
             atrEntry, adxEntry, balPre, balPost, durMin, _beActivated);
}

//══════════════════════════════════════════════════════════════════════════════
//  UTILIDADES
//══════════════════════════════════════════════════════════════════════════════

bool HasOpenPosition()
{
    for(int i = 0; i < PositionsTotal(); i++)
    {
        if(!PosInfo.SelectByIndex(i)) continue;
        if(PosInfo.Magic() == Inp_MagicNumber && PosInfo.Symbol() == _sym) return true;
    }
    return false;
}

void UpdateDailyCounter()
{
    MqlDateTime dt;
    TimeToStruct(TimeCurrent(), dt);
    dt.hour = 0; dt.min = 0; dt.sec = 0;
    datetime today = StructToTime(dt);

    if(today != _currentDay)
    {
        _currentDay   = today;
        _tradesToday  = 0;
    }
}

//══════════════════════════════════════════════════════════════════════════════
//  LOGGING CSV
//══════════════════════════════════════════════════════════════════════════════

void InitCSV()
{
    MqlDateTime dt;
    TimeToStruct(TimeCurrent(), dt);
    _csvFile = StringFormat("%s_%04d%02d%02d_%02d%02d.csv",
                            Inp_CSVBaseName, dt.year, dt.mon, dt.day, dt.hour, dt.min);

    _csvHandle = FileOpen(_csvFile, FILE_WRITE | FILE_CSV | FILE_COMMON, ',');
    if(_csvHandle == INVALID_HANDLE)
    {
        Print("WARNING: No se pudo crear CSV de logging");
        return;
    }

    FileWrite(_csvHandle,
              "Ticket", "PositionID", "FechaApertura", "FechaCierre",
              "PrecioEntrada", "PrecioCierre", "PnL_Neto_USD",
              "Resultado", "ATR_Entrada", "ADX_Entrada",
              "Balance_Pre", "Balance_Post", "Duracion_Min", "BE_Activado");
    FileFlush(_csvHandle);
    PrintFormat("CSV iniciado: %s (carpeta Common de MT5)", _csvFile);
}

void LogTrade(ulong ticket, ulong posID,
              datetime openT, datetime closeT,
              double openP, double closeP, double netPnL,
              string resultado, double atrEntry, double adxEntry,
              double balPre, double balPost, long durMin, bool beAct)
{
    if(_csvHandle == INVALID_HANDLE) return;

    FileWrite(_csvHandle,
              IntegerToString((long)ticket),
              IntegerToString((long)posID),
              TimeToString(openT,  TIME_DATE|TIME_MINUTES),
              TimeToString(closeT, TIME_DATE|TIME_MINUTES),
              DoubleToString(openP,  _digits),
              DoubleToString(closeP, _digits),
              DoubleToString(netPnL, 2),
              resultado,
              DoubleToString(atrEntry, 4),
              DoubleToString(adxEntry, 2),
              DoubleToString(balPre,  2),
              DoubleToString(balPost, 2),
              IntegerToString(durMin),
              beAct ? "SI" : "NO");
    FileFlush(_csvHandle);
}
