{"language": "javascript", "code": "const { Document, Packer, Paragraph, TextRun, Table, TableRow, TableCell,
        HeadingLevel, AlignmentType, BorderStyle, WidthType, ShadingType,
        LevelFormat, PageNumber, PageBreak, VerticalAlign } = require('docx');
const fs = require('fs');

// ─── COLOR PALETTE ────────────────────────────────────────────────────────────
const C = {
  navy:    "1F3864",
  blue:    "2E75B6",
  lblue:   "BDD7EE",
  llblue:  "DEEAF1",
  green:   "375623",
  lgreen:  "E2EFDA",
  red:     "C00000",
  lred:    "FCE4D6",
  amber:   "7F6000",
  lamber:  "FFF2CC",
  gray:    "595959",
  lgray:   "F2F2F2",
  white:   "FFFFFF",
  yellow:  "FFD966",
};

const border = (color="CCCCCC") => ({ style: BorderStyle.SINGLE, size: 6, color });
const cellBorders = (color="CCCCCC") => ({
  top: border(color), bottom: border(color),
  left: border(color), right: border(color)
});

function h1(text, color=C.navy) {
  return new Paragraph({
    heading: HeadingLevel.HEADING_1,
    children: [new TextRun({ text, bold: true, color, font: "Arial", size: 30 })],
    spacing: { before: 360, after: 120 },
    border: { bottom: { style: BorderStyle.SINGLE, size: 12, color: C.blue, space: 4 } }
  });
}

function h2(text) {
  return new Paragraph({
    heading: HeadingLevel.HEADING_2,
    children: [new TextRun({ text, bold: true, color: C.navy, font: "Arial", size: 26 })],
    spacing: { before: 280, after: 100 }
  });
}

function h3(text) {
  return new Paragraph({
    heading: HeadingLevel.HEADING_3,
    children: [new TextRun({ text, bold: true, color: C.blue, font: "Arial", size: 22 })],
    spacing: { before: 200, after: 80 }
  });
}

function para(runs, spacing={ before: 60, after: 60 }) {
  const children = runs.map(r => {
    if(typeof r === 'string') return new TextRun({ text: r, font: "Arial", size: 20 });
    return new TextRun({ font: "Arial", size: 20, ...r });
  });
  return new Paragraph({ children, spacing });
}

function bullet(text, bold=false, color=null) {
  return new Paragraph({
    numbering: { reference: "bullets", level: 0 },
    children: [new TextRun({ text, bold, color: color||undefined, font: "Arial", size: 20 })],
    spacing: { before: 40, after: 40 }
  });
}

function code(text) {
  return new Paragraph({
    children: [new TextRun({ text, font: "Courier New", size: 18, color: C.navy })],
    spacing: { before: 40, after: 40 },
    shading: { fill: "F5F5F5", type: ShadingType.CLEAR },
    indent: { left: 360 }
  });
}

function note(text, bgColor=C.lamber, textColor=C.amber) {
  return new Paragraph({
    children: [new TextRun({ text: "⚠  " + text, bold: true, color: textColor, font: "Arial", size: 20 })],
    spacing: { before: 80, after: 80 },
    shading: { fill: bgColor, type: ShadingType.CLEAR },
    indent: { left: 360, right: 360 }
  });
}

function ok(text) {
  return new Paragraph({
    children: [new TextRun({ text: "✓  " + text, bold: true, color: C.green, font: "Arial", size: 20 })],
    spacing: { before: 40, after: 40 },
    indent: { left: 360 }
  });
}

function invariant(text) {
  return new Paragraph({
    children: [new TextRun({ text: "🔒  " + text, bold: true, color: C.red, font: "Arial", size: 20 })],
    spacing: { before: 40, after: 40 },
    indent: { left: 360 }
  });
}

function pageBreak() {
  return new Paragraph({ children: [new PageBreak()] });
}

function spacer(n=1) {
  return Array(n).fill(new Paragraph({ children: [new TextRun("")], spacing: { before: 40, after: 40 } }));
}

// ─── TABLE HELPERS ────────────────────────────────────────────────────────────
function headerCell(text, bgColor=C.navy, textColor=C.white, width=2000) {
  return new TableCell({
    borders: cellBorders(C.navy),
    shading: { fill: bgColor, type: ShadingType.CLEAR },
    width: { size: width, type: WidthType.DXA },
    margins: { top: 80, bottom: 80, left: 100, right: 100 },
    children: [new Paragraph({
      alignment: AlignmentType.CENTER,
      children: [new TextRun({ text, bold: true, color: textColor, font: "Arial", size: 18 })]
    })]
  });
}

function dataCell(text, bgColor=C.white, textColor="000000", width=2000, align=AlignmentType.LEFT) {
  return new TableCell({
    borders: cellBorders(),
    shading: { fill: bgColor, type: ShadingType.CLEAR },
    width: { size: width, type: WidthType.DXA },
    margins: { top: 70, bottom: 70, left: 100, right: 100 },
    children: [new Paragraph({
      alignment: align,
      children: [new TextRun({ text, color: textColor, font: "Arial", size: 18 })]
    })]
  });
}

function simpleTable(headers, rows, colWidths, headerBg=C.navy) {
  const totalW = colWidths.reduce((a,b)=>a+b, 0);
  return new Table({
    width: { size: totalW, type: WidthType.DXA },
    columnWidths: colWidths,
    rows: [
      new TableRow({ tableHeader: true,
        children: headers.map((h,i) => headerCell(h, headerBg, C.white, colWidths[i])) }),
      ...rows.map((row, ri) =>
        new TableRow({ children: row.map((cell, ci) => {
          const bg = ri % 2 === 0 ? C.white : C.lgray;
          if(typeof cell === 'object' && cell.text !== undefined)
            return dataCell(cell.text, cell.bg||bg, cell.fg||"000000", colWidths[ci], cell.align||AlignmentType.LEFT);
          return dataCell(String(cell), bg, "000000", colWidths[ci]);
        })})
      )
    ]
  });
}

