   594	bool FindBullishFVG(const MqlRates &rates[], int lookback, double &fvgMidpoint)
   595	{
   596	    // Un FVG alcista existe cuando:
   597	    // rates[i+2].high < rates[i].low  (gap entre el máximo de 2 velas atrás y mínimo de vela actual)
   598	    // El gap debe tener tamaño >= FVG_MinSizePrice
   599	    // Se retorna el midpoint del gap como nivel de soporte FVG
   600	
   601	    int maxIdx = MathMin(lookback - 1, ArraySize(rates) - 3);
   602	    for(int i = 0; i <= maxIdx; i++)
   603	    {
   604	        double gapBottom = rates[i+2].high;  // Máximo de la vela más vieja del gap
   605	        double gapTop    = rates[i].low;     // Mínimo de la vela más reciente
   606	
   607	        if(gapTop > gapBottom)
   608	        {
   609	            double gapSize = gapTop - gapBottom;
   610	            if(gapSize >= Inp_FVG_MinSizePrice)
   611	            {
   612	                fvgMidpoint = (gapTop + gapBottom) / 2.0;
   613	                return true;
   614	            }
   615	        }
   616	    }
   617	    return false;
   618	}
