bool IsInSession()
{
    MqlDateTime dt;
    TimeToStruct(TimeCurrent(), dt);

    bool edt = (Inp_AutoDST) ? IsEdtPeriod(dt) : false;

    // S1 — NYSE Open
    int sh1 = edt ? Inp_SessSummer_H : Inp_SessWinter_H;
    int sm1 = edt ? Inp_SessSummer_M : Inp_SessWinter_M;
    int nowMin    = dt.hour * 60 + dt.min;
    int startMin1 = sh1 * 60 + sm1;
    int endMin1   = startMin1 + Inp_SessDurationMin;
    if(nowMin >= startMin1 && nowMin < endMin1) return true;

    // S2 — London Close
    if(Inp_Sess2_Enable)
    {
        int sh2 = edt ? Inp_Sess2Summer_H : Inp_Sess2Winter_H;
        int sm2 = edt ? Inp_Sess2Summer_M : Inp_Sess2Winter_M;
        int startMin2 = sh2 * 60 + sm2;
        int endMin2   = startMin2 + Inp_Sess2DurationMin;
        if(nowMin >= startMin2 && nowMin < endMin2) return true;
    }

    return false;
}

